function solve(n, edges, k) {
    edges.sort((a, b) => a[2] - b[2]);
    let low = 0;
    let high = Math.max(...edges.map(e => e[2]));
    let answer = high;

    function countComponents(X) {
        let parent = Array(n).fill(0).map((_, i) => i);
        let rank = Array(n).fill(1);

        function find(u) {
            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }

        function union(u, v) {
            let rootU = find(u);
            let rootV = find(v);
            if (rootU !== rootV) {
                if (rank[rootU] > rank[rootV]) {
                    parent[rootV] = rootU;
                } else {
                    parent[rootU] = rootV;
                    if (rank[rootU] === rank[rootV]) {
                        rank[rootV]++;
                    }
                }
            }
        }

        for (let e of edges) {
            if (e[2] <= X) {
                union(e[0], e[1]);
            }
        }

        let roots = new Set();
        for (let i = 0; i < n; i++) {
            roots.add(find(i));
        }
        return roots.size;
    }

    while (low <= high) {
        let mid = Math.floor((low + high) / 2);
        let components = countComponents(mid);
        if (components <= k) {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    return answer;
}

