def solve(n: Long, edges: Array[Array[Long]], k: Long): Long = {
    val sortedEdges = edges.sortWith((a, b) => a(2) < b(2))
    val maxWeight = sortedEdges.max(_.apply(2))
    var low = 0L
    var high = maxWeight
    var answer = maxWeight

    def countComponents(X: Long): Int = {
        val parent = Array.fill(n.toInt)(0)
        val rank = Array.fill(n.toInt)(1)
        for (i <- 0 until n.toInt) {
            parent(i) = i
        }

        def find(u: Int): Int = {
            if (parent(u) != u) {
                parent(u) = find(parent(u))
            }
            parent(u)
        }

        def union(u: Int, v: Int): Unit = {
            val rootU = find(u)
            val rootV = find(v)
            if (rootU != rootV) {
                if (rank(rootU) > rank(rootV)) {
                    parent(rootV) = rootU
                } else {
                    parent(rootU) = rootV
                    if (rank(rootU) == rank(rootV)) {
                        rank(rootV) += 1
                    }
                }
            }
        }

        for (edge <- sortedEdges) {
            if (edge(2) <= X) {
                union(edge(0).toInt, edge(1).toInt)
            }
        }

        val roots = scala.collection.mutable.Set[Int]()
        for (i <- 0 until n.toInt) {
            roots.add(find(i))
        }
        roots.size
    }

    while (low <= high) {
        val mid = (low + high) / 2
        val components = countComponents(mid)
        if (components <= k) {
            answer = mid
            high = mid - 1
        } else {
            low = mid + 1
        }
    }

    answer
}
